        combined_params.update(extra_params)

        payload = {
            "stream": False,
        }

        # =========================================================
        # 1. 构建 Messages (Chat 格式)
        # =========================================================
        if isinstance(prompt, list):
            payload["messages"] = prompt
        else:
            # 纯文本包装
            payload["messages"] = [{"role": "user", "content": [{"type": "text", "text": prompt}]}]

        # =========================================================
        # 2. 多模态数据处理（图像或视频）
        # =========================================================
        media_data = extra_info.get("image_data", [])  # 这里可能包含图像或视频路径
