                            continue

                        video_b64 = video_to_base64(video_path)
                        video_format = get_video_format(video_path)
                        video_url = f"data:video/{video_format};base64,{video_b64}"
                        base64_videos.append(video_url)

                        self.logger.info(f"[vLLMWorker] Encoded video: {video_path} (format: {video_format})")
