        # 3. 清理 messages 中的非标准字段
        # =========================================================
        for msg in payload["messages"]:
            if "content" in msg and isinstance(msg["content"], list):
                for item in msg["content"]:
                    # 清理 image_url 中的非标准字段
                    if item.get("type") == "image_url" and "image_url" in item:
                        if "image_wh" in item["image_url"]:
                            del item["image_url"]["image_wh"]
                    # 清理 video_url 中的非标准字段
                    if item.get("type") == "video_url" and "video_url" in item:
                        # 只保留 url 字段
                        if isinstance(item["video_url"], dict):
                            item["video_url"] = {"url": item["video_url"].get("url", "")}

        # =========================================================
        # 4. 工具调用（只在有效时添加）
        # =========================================================
        if tools and len(tools) > 0:
            payload["tools"] = tools

        if tool_choice and tool_choice.strip():
            payload["tool_choice"] = tool_choice

        # =========================================================
        # 5. 参数映射（严格白名单）
        # =========================================================
        VLLM_VALID_PARAMS = {
            "temperature": float,
            "top_p": float,
            "top_k": int,
            "max_tokens": int,
            "n": int,
            "logprobs": bool,
            "top_logprobs": int,
            "stop": list,
            "presence_penalty": float,
            "frequency_penalty": float,
            "repetition_penalty": float,
            "seed": int,
            "user": str,
            "best_of": int,
            "use_beam_search": bool,
        }

        param_mapping = {
            "stops": "stop",
            "max_new_tokens": "max_tokens",
            "return_logprob": "logprobs",
        }

        # 应用映射
        for key, value in combined_params.items():
            # 跳过不支持的参数
            if key in [
                "min_tokens", "stop_token_ids", "skip_special_tokens",
                "include_stop_str_in_output", "no_stop_trim", 
                "return_token_ids", "spaces_between_special_tokens", "stream"
            ]:
                continue

            new_key = param_mapping.get(key, key)

            if new_key in VLLM_VALID_PARAMS:
                target_type = VLLM_VALID_PARAMS[new_key]

                if new_key == "logprobs":
                    if value:
                        payload["logprobs"] = True
                        payload["top_logprobs"] = 1
                elif new_key == "stop":
                    if value:
                        payload["stop"] = value if isinstance(value, list) else [value]
                else:
                    try:
                        if target_type == bool:
                            payload[new_key] = bool(value)
                        elif target_type == int:
                            payload[new_key] = int(value)
                        elif target_type == float:
                            payload[new_key] = float(value)
                        else:
                            payload[new_key] = value
                    except (ValueError, TypeError):
                        self.logger.warning(f"[vLLMWorker] Failed to convert {new_key}={value} to {target_type}")

        # =========================================================
        # 6. 最终清理
        # =========================================================
        payload = {k: v for k, v in payload.items() if v is not None and v != ""}

        if "stop" in payload and not payload["stop"]:
            del payload["stop"]

        # =========================================================
        # 7. 发送请求
        # =========================================================
        if not url.endswith("chat/completions"):
            request_url = f"{url.rstrip('/')}/v1/chat/completions"
        else:
            request_url = url

        # 调试输出
        self.logger.debug(f"[vLLMWorker] Request URL: {request_url}")
        self.logger.debug(f"[vLLMWorker] Payload keys: {list(payload.keys())}")

        # 只打印消息结构，不打印 base64 数据（太长）
        messages_debug = []
        for msg in payload["messages"]:
            content_types = []
            if isinstance(msg.get("content"), list):
                for item in msg["content"]:
                    content_types.append(item.get("type", "unknown"))
            messages_debug.append({
                "role": msg.get("role"),
                "content_types": content_types
            })
        self.logger.info(f"[vLLMWorker] Messages structure: {messages_debug}")

        try:
            return await self._safe_post_request(request_url, headers, payload)
        except Exception as e:
            self.logger.error(f"[vLLMWorker] Request failed!")
            self.logger.error(f"URL: {request_url}")
            if hasattr(e, 'response') and e.response is not None:
                self.logger.error(f"Server Response: {e.response.text}")
            raise e

    def offload(self, block: bool = True):
        """Offload worker resources"""
        try:
            import gc
            gc.collect()

            try:
                import torch
                if torch.cuda.is_available():
                    torch.cuda.empty_cache()
            except:
                pass

            self.logger.info(f"[vLLMWorker] Offload completed")
            return True
        except Exception as e:
            self.logger.error(f"[vLLMWorker] Offload error: {e}")
            return True
```

## 主要改动

1. **分别处理两个字段**：
   - `video_data` - 视频路径
   - `image_data` - 图像路径

2. **优先级规则**：
   - 如果 `video_data` 存在，则处理视频（忽略 `image_data`）
   - 如果只有 `image_data` 存在，则处理图像
   - 如果都不存在，只发送文本

3. **使用示例**：

```python
# 视频数据
extra_info = {
    "video_data": ["/path/to/video.mp4"],
    # 或多个视频
    # "video_data": ["/path/to/video1.mp4", "/path/to/video2.mp4"],
}

# 图像数据
extra_info = {
    "image_data": ["/path/to/image.jpg"],
    # 或多个图像
    # "image_data": ["/path/to/img1.jpg", "/path/to/img2.jpg"],
}

# 如果同时存在，优先视频
extra_info = {
    "video_data": ["/path/to/video.mp4"],
    "image_data": ["/path/to/image.jpg"],  # 会被忽略
}
```

4. **日志输出**会清楚地显示处理的是视频还是图像：
```
[vLLMWorker] Processing video data: 1 file(s)
[vLLMWorker] Encoded video: /path/to/video.mp4 (format: mp4)
[vLLMWorker] Messages structure: [{'role': 'user', 'content_types': ['video_url', 'text']}]
```

现在可以正确处理你的视频数据了！
